import React, { useState, useEffect } from 'react';
import { attendanceAPI, departmentAPI } from '../utils/api';
import toast from 'react-hot-toast';
import './ReportsPage.css';

function saveBlob(blob, filename) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  URL.revokeObjectURL(url);
}

export default function ReportsPage() {
  const today = new Date().toISOString().slice(0, 10);
  const [dateFrom, setDateFrom] = useState(today);
  const [dateTo, setDateTo]     = useState(today);
  const [records, setRecords]   = useState([]);
  const [loading, setLoading]   = useState(false);
  const [exporting, setExporting] = useState('');

  const fetchRecords = async () => {
    setLoading(true);
    try {
      const res = await attendanceAPI.list({
        timestamp__date__gte: dateFrom,
        timestamp__date__lte: dateTo,
      });
      setRecords(res.data.results || res.data);
    } finally { setLoading(false); }
  };

  useEffect(() => { fetchRecords(); }, []);

  const exportExcel = async () => {
    setExporting('excel');
    try {
      const res = await attendanceAPI.exportExcel(dateFrom, dateTo);
      saveBlob(res.data, `attendance_${dateFrom}_${dateTo}.xlsx`);
      toast.success('Excel exported!');
    } catch { toast.error('Export failed'); }
    finally { setExporting(''); }
  };

  const exportPDF = async () => {
    setExporting('pdf');
    try {
      const res = await attendanceAPI.exportPDF(dateFrom, dateTo);
      saveBlob(res.data, `attendance_${dateFrom}_${dateTo}.pdf`);
      toast.success('PDF exported!');
    } catch { toast.error('Export failed'); }
    finally { setExporting(''); }
  };

  const known   = records.filter(r => !r.is_unknown);
  const unknown = records.filter(r => r.is_unknown);

  return (
    <div>
      <div className="page-header">
        <h1>📋 Reports</h1>
        <p>Filter and export attendance records</p>
      </div>

      {/* Filter + Export bar */}
      <div className="card" style={{ marginBottom: 20 }}>
        <div className="report-filter-bar">
          <div>
            <label>Date From</label>
            <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} />
          </div>
          <div>
            <label>Date To</label>
            <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} />
          </div>
          <div style={{ display: 'flex', alignItems: 'flex-end', gap: 10 }}>
            <button className="btn btn-primary" onClick={fetchRecords} disabled={loading}>
              {loading ? '⏳' : '🔍'} Search
            </button>
            <button className="btn btn-success" onClick={exportExcel} disabled={exporting === 'excel'}>
              {exporting === 'excel' ? '⏳' : '📊'} Excel
            </button>
            <button className="btn btn-danger" onClick={exportPDF} disabled={exporting === 'pdf'}>
              {exporting === 'pdf' ? '⏳' : '📄'} PDF
            </button>
          </div>
        </div>
      </div>

      {/* Summary cards */}
      <div className="grid-3" style={{ marginBottom: 20 }}>
        <div className="card rpt-stat">
          <div style={{ fontSize: 28, color: '#3b82f6', fontWeight: 700 }}>{records.length}</div>
          <div style={{ color: '#94a3b8', fontSize: 13 }}>Total Records</div>
        </div>
        <div className="card rpt-stat">
          <div style={{ fontSize: 28, color: '#10b981', fontWeight: 700 }}>{known.length}</div>
          <div style={{ color: '#94a3b8', fontSize: 13 }}>Known Persons</div>
        </div>
        <div className="card rpt-stat">
          <div style={{ fontSize: 28, color: '#ef4444', fontWeight: 700 }}>{unknown.length}</div>
          <div style={{ color: '#94a3b8', fontSize: 13 }}>Unknown Detections</div>
        </div>
      </div>

      {/* Records table */}
      <div className="card">
        <div className="card-title">Attendance Records ({records.length})</div>
        <div className="report-table-wrap">
          <table className="live-table">
            <thead>
              <tr>
                <th>#</th><th>Date</th><th>Time</th><th>Emp ID</th>
                <th>Name</th><th>Khmer Name</th><th>Department</th>
                <th>Camera</th><th>Confidence</th><th>Status</th>
              </tr>
            </thead>
            <tbody>
              {records.map((r, i) => (
                <tr key={r.id} className={r.is_unknown ? 'row-unknown' : ''}>
                  <td style={{ color: '#475569' }}>{i + 1}</td>
                  <td>{new Date(r.timestamp).toLocaleDateString()}</td>
                  <td>{new Date(r.timestamp).toLocaleTimeString()}</td>
                  <td><code style={{ color: '#60a5fa' }}>{r.employee_id || '—'}</code></td>
                  <td>{r.is_unknown ? <span style={{ color: '#ef4444' }}>Unknown</span> : r.employee_name}</td>
                  <td style={{ fontFamily: 'serif' }}>{r.employee_name_kh || '—'}</td>
                  <td>{r.department || '—'}</td>
                  <td>{r.camera_name || '—'}</td>
                  <td>{r.confidence ? `${(r.confidence * 100).toFixed(1)}%` : '—'}</td>
                  <td>
                    <span className={`badge ${r.is_unknown ? 'badge-red' : 'badge-green'}`}>
                      {r.is_unknown ? 'Unknown' : r.status || 'Check In'}
                    </span>
                  </td>
                </tr>
              ))}
              {records.length === 0 && !loading && (
                <tr><td colSpan={10} style={{ textAlign: 'center', padding: 40, color: '#475569' }}>
                  No records found for selected dates
                </td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
